content.problemStatement:
Let's learn about inserting new elements at the beginning of a linked list.

Now, suppose we have a linked list `1 -&gt; 2 -&gt; 3` and we want to insert 4 at the beginning.
We can then follow these steps:


.problem-images {
  display: block;
  margin: 10px auto 10px auto;
}

Create a new node with value 4. Let's call it `newNode`

Add the **head** of the existing linked list as the **next** of `newNode`.

Then set the **head** variable to the `newNode`, as the `newNode` is our new **head**.
ImplementationTo implement insertion operation, we have to create a new class **LinkedList** and create a new method **insertFront** in it.

We have also added **getHeadValue** to get the value at head after insertion.

Read and understand the code and then submit to see what it does.

code.C:
#include <stdio.h>
#include <stdlib.h>

struct Node { int value; struct Node* next; };
struct LinkedList { struct Node* head; };

struct Node* createNode(int v) {
    struct Node* n = (struct Node*)malloc(sizeof(struct Node));
    n->value = v; n->next = NULL; return n;
}

void insertFront(struct LinkedList* list, int v) {
    struct Node* n = createNode(v);
    n->next = list->head;
    list->head = n;
}

void printList(struct LinkedList* list) {
    struct Node* cur = list->head;
    while (cur) { printf("%d ", cur->value); cur = cur->next; }
    printf("\n");
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        struct LinkedList lst; lst.head = NULL;
        for (int i=0;i<N;++i) { int v; scanf("%d", &v); insertFront(&lst, v); }
        int X; scanf("%d", &X);
        insertFront(&lst, X);
        printList(&lst);
    }
    return 0;
}

code.C++:
#include <bits/stdc++.h>
using namespace std;

class Node {
public:
    int value; Node* next;
    Node(int v): value(v), next(nullptr) {}
};

class LinkedList {
public:
    Node* head = nullptr;
    void insertFront(int v) {
        Node* n = new Node(v);
        n->next = head;
        head = n;
    }
    void print() const {
        for (Node* cur = head; cur; cur = cur->next) cout << cur->value << ' ';
        cout << '\n';
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while (T--) {
        int N; cin>>N;
        LinkedList lst;
        for (int i=0;i<N;++i) { int v; cin>>v; lst.insertFront(v); }
        int X; cin>>X; lst.insertFront(X);
        lst.print();
    }
    return 0;
}

code.Java:
import java.io.*;
import java.util.*;

public class Main {
    static class Node {
        int value; Node next;
        Node(int v) { value = v; next = null; }
    }
    static class LinkedList {
        Node head = null;
        void insertFront(int v) {
            Node n = new Node(v);
            n.next = head;
            head = n;
        }
        void print(PrintWriter out) {
            for (Node cur = head; cur != null; cur = cur.next) out.print(cur.value + " ");
            out.println();
        }
    }
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        PrintWriter out = new PrintWriter(new BufferedWriter(new OutputStreamWriter(System.out)));
        int T = Integer.parseInt(br.readLine().trim());
        while (T-- > 0) {
            int N = Integer.parseInt(br.readLine().trim());
            StringTokenizer st = new StringTokenizer(br.readLine());
            LinkedList lst = new LinkedList();
            for (int i = 0; i < N; ++i) {
                int v = Integer.parseInt(st.nextToken());
                lst.insertFront(v);
            }
            int X = Integer.parseInt(br.readLine().trim());
            lst.insertFront(X);
            lst.print(out);
        }
        out.flush();
    }
}

